  { id:20, emoji:'🥗', name:'有机糙米健康套餐',  shop:'轻食工坊',           price:42,   sales:350,   keywords:['米饭','健康','有机','糙米'], tags:{health:'高',price:'中',quality:'精品',taste:'清淡'} },
  { id:21, emoji:'🍱', name:'学生快手拌饭',     shop:'食堂来了',            price:10.9, sales:9800,  keywords:['米饭','拌饭','学生','便宜'], tags:{health:'低',price:'低',quality:'大众',taste:'咸鲜'} },
