      <div class="user-btn-desc">${u.desc}</div>
    </button>
  `).join('');
}

// ============================================================
// 选择用户
// ============================================================
function selectUser(userId) {
  const user = USERS.find(u => u.id === userId);
  if (!user) return;

  const prevUser = currentUser;
  currentUser = user;

  document.querySelectorAll('.user-btn').forEach(b => b.classList.remove('active'));
  document.getElementById(`ubtn-${userId}`).classList.add('active');
  document.getElementById('appUser').textContent = `${user.avatar} ${user.name}`;
  document.getElementById('appSearchInput').placeholder = `搜索${user.name}喜欢的...`;

  if (prevUser && prevUser.id !== userId) {
    stats.switch++;
    addLog('switch', user, `从 ${prevUser.avatar}${prevUser.name} 切换到 ${user.avatar}${user.name}`, `偏好: 健康${user.weights.health['高']}x / 低价${user.weights.price['低']}x / 辣味${user.weights.taste['辣']}x`);
  }

  renderProfile(user);
  renderWeights(user);
  updateBehaviorInfer();

  // 刷新当前搜索结果
  if (currentKw) doSearch(currentKw);
  if (currentTab === 'reco') renderRecoTab();
}

