// ============================================================
// 搜索逻辑
// ============================================================
function doSearch(kw) {
  if (!currentUser) {
    alert('请先选择用户！');
    return;
  }
  currentKw = kw;
  currentTab = 'search';

  // 更新按钮
  document.querySelectorAll('.kw-btn').forEach(b => b.classList.remove('active'));
  const kb = document.getElementById(`kbtn-${kw}`);
  if (kb) kb.classList.add('active');
  document.getElementById('appSearchInput').value = kw;

  // 更新 tab
  document.querySelectorAll('.app-tab').forEach(t => t.classList.remove('active'));
  document.querySelector('.app-tab').classList.add('active');

  // 记录行为
  stats.search++;
  stats.kw.add(kw);
  if (!searchHistory[currentUser.id]) searchHistory[currentUser.id] = [];
  searchHistory[currentUser.id].push(kw);

  addLog('search', currentUser, `搜索「${kw}」`, `权重: 健康${currentUser.weights.health['高']}x 低价${currentUser.weights.price['低']}x 辣${currentUser.weights.taste['辣']}x`);

  // 过滤 + 排序
  const matched = PRODUCTS.filter(p => p.keywords.some(k2 => k2.includes(kw) || kw.includes(k2)));
  const uid = currentUser.id;
  const clicks = clickedProducts[uid] || {};

  const ranked = matched.map(p => {
    const clickBoost = (clicks[p.id] || 0) * 0.3;
    return { ...p, score: scoreProduct(p, currentUser, clickBoost), reason: getReason(p, currentUser) };
  }).sort((a, b) => b.score - a.score);

  renderAppProducts(ranked);
  renderBehaviorReco();
  updateBehaviorInfer();
}

function doAppSearch() {
  const val = document.getElementById('appSearchInput').value.trim();
  if (!val) return;
  // 尝试匹配关键词
  const found = KEYWORDS.find(k => k.kw === val || val.includes(k.kw));
  if (found) doSearch(found.kw);
  else {
    // 自由搜索
    if (!currentUser) { alert('请先选择用户！'); return; }
    currentKw = val;
    stats.search++;
    stats.kw.add(val);
    if (!searchHistory[currentUser.id]) searchHistory[currentUser.id] = [];
    searchHistory[currentUser.id].push(val);
    addLog('search', currentUser, `搜索「${val}」（自由搜索）`, '');
    const matched = PRODUCTS.filter(p => p.name.includes(val) || p.keywords.some(k=>k.includes(val)));
    const ranked = matched.map(p => ({...p, score:scoreProduct(p,currentUser,0), reason:getReason(p,currentUser)})).sort((a,b)=>b.score-a.score);
    renderAppProducts(ranked);
  }
}

// ============================================================
// 渲染 APP 商品列表
// ============================================================
function renderAppProducts(ranked) {
  if (!ranked.length) {
    document.getElementById('appProducts').innerHTML = '<div class="app-empty">😕 没有匹配商品</div>';
    return;
  }
  document.getElementById('appProducts').innerHTML = ranked.map((p, i) => `
    <div class="app-product-item r${i+1}" onclick="clickProduct(${p.id})">
      <div class="app-item-emoji">${p.emoji}</div>
      <div class="app-item-body">
        <div class="app-item-name">${p.name} ${i<3?`<span class="rank-badge">#${i+1}</span>`:''}</div>
        <div class="app-item-shop">${p.shop}</div>
        <div><span class="app-item-tag">${p.reason}</span></div>
      </div>
      <div class="app-item-price">¥${p.price}</div>
    </div>
  `).join('');
}

// ============================================================
// 点击商品
// ============================================================
function clickProduct(productId) {
  if (!currentUser) return;
  const p = PRODUCTS.find(p => p.id === productId);
  if (!p) return;
  const uid = currentUser.id;
  if (!clickedProducts[uid]) clickedProducts[uid] = {};
  clickedProducts[uid][productId] = (clickedProducts[uid][productId] || 0) + 1;

  stats.click++;
  addLog('click', currentUser, `点击「${p.emoji}${p.name}」¥${p.price}`,
    `健康:${p.tags.health} 价格:${p.tags.price} 品质:${p.tags.quality} 口味:${p.tags.taste} · 本次第${clickedProducts[uid][productId]}次`);

  // 刷新行为推荐
  renderBehaviorReco();
  updateBehaviorInfer();

  // 视觉反馈
  const items = document.querySelectorAll('.app-product-item');
  items.forEach(item => {
    if (item.getAttribute('onclick') === `clickProduct(${productId})`) {
      item.style.background = '#e8f5e9';
      setTimeout(() => { item.style.background = ''; }, 600);
    }
  });
}

// ============================================================
// 行为增强推荐（结合历史点击 + 标签权重）
// ============================================================
function renderBehaviorReco() {
  if (!currentUser) return;
  const uid = currentUser.id;
  const clicks = clickedProducts[uid] || {};

  if (Object.keys(clicks).length === 0) {
    document.getElementById('behaviorReco').innerHTML =
      '<div style="color:#ccc;font-size:12px;text-align:center;padding:16px">点击商品后，此处生成行为增强推荐</div>';
    return;
  }

  // 推断用户实时偏好（从点击历史）
  const clickedList = Object.entries(clicks).map(([id, cnt]) => ({p: PRODUCTS.find(p=>p.id===parseInt(id)), cnt})).filter(x=>x.p);
  const healthCount = {}, priceCount = {}, tasteCount = {}, qualityCount = {};
  clickedList.forEach(({p, cnt}) => {
    healthCount[p.tags.health] = (healthCount[p.tags.health]||0) + cnt;
    priceCount[p.tags.price] = (priceCount[p.tags.price]||0) + cnt;
    tasteCount[p.tags.taste] = (tasteCount[p.tags.taste]||0) + cnt;
    qualityCount[p.tags.quality] = (qualityCount[p.tags.quality]||0) + cnt;
  });

  // 动态权重 = 标签权重 * 0.6 + 行为推断权重 * 0.4
  function behaviorWeight(dim, val) {
    const total = Object.values(dim).reduce((a,b)=>a+b,0)||1;
    return (dim[val]||0) / total;
  }

  const clickedIds = new Set(Object.keys(clicks).map(Number));
  const scored = PRODUCTS
    .filter(p => !clickedIds.has(p.id)) // 过滤已点击过的
    .map(p => {
      const baseScore = scoreProduct(p, currentUser, 0);
      const behaviorBoost =
        behaviorWeight(healthCount, p.tags.health) * 1.5 +
        behaviorWeight(priceCount, p.tags.price) * 1.5 +
        behaviorWeight(tasteCount, p.tags.taste) * 1.2 +
        behaviorWeight(qualityCount, p.tags.quality) * 1.0;
      const finalScore = baseScore * 0.6 + behaviorBoost * 3.0;
      const reasons = [];
      if (behaviorWeight(healthCount, p.tags.health) > 0.4) reasons.push('与你点击过的健康度一致');
      if (behaviorWeight(priceCount, p.tags.price) > 0.4) reasons.push('符合你的价格偏好');
      if (behaviorWeight(tasteCount, p.tags.taste) > 0.4) reasons.push('口味与历史相符');
      const reasonText = reasons[0] || '综合画像 + 行为推断';
      return { ...p, finalScore, reasonText };
    })
    .sort((a, b) => b.finalScore - a.finalScore)
    .slice(0, 4);

  if (!scored.length) {
    document.getElementById('behaviorReco').innerHTML = '<div style="color:#ccc;font-size:12px;text-align:center;padding:16px">暂无可推荐商品（已浏览全部）</div>';
    return;
  }

  document.getElementById('behaviorReco').innerHTML = `
    <div class="behavior-reco-list">
      ${scored.map((p,i) => `
        <div class="reco-item behavior-boost" onclick="clickProduct(${p.id})">
          <div class="reco-emoji">${p.emoji}</div>
          <div class="reco-info">
            <div class="reco-name">${p.name}</div>
            <div class="reco-reason">${p.reasonText}</div>
          </div>
          <div>
            <div class="reco-price">¥${p.price}</div>
            ${i===0?'<div style="text-align:right"><span class="boost-tag">🎯推荐</span></div>':''}
          </div>
        </div>
      `).join('')}
    </div>
    <div style="font-size:10px;color:#bbb;margin-top:8px;text-align:center">基于 ${Object.values(clicks).reduce((a,b)=>a+b,0)} 次点击行为 + Persona 标签综合计算</div>
  `;
}

// ============================================================
// "为你推荐" tab
// ============================================================
function switchTab(tab, el) {
  currentTab = tab;
  document.querySelectorAll('.app-tab').forEach(t => t.classList.remove('active'));
  el.classList.add('active');
  if (tab === 'reco') renderRecoTab();
  else if (currentKw) doSearch(currentKw);
  else document.getElementById('appProducts').innerHTML = '<div class="app-empty">👆 点击关键词搜索</div>';
}

function renderRecoTab() {
  if (!currentUser) {
    document.getElementById('appProducts').innerHTML = '<div class="app-empty">请先选择用户</div>';
    return;
  }
  const uid = currentUser.id;
  const clicks = clickedProducts[uid] || {};
  const clickedIds = new Set(Object.keys(clicks).map(Number));

  // 全量商品，基于画像 + 行为排序
  const scored = PRODUCTS.map(p => {
    const clickBoost = (clicks[p.id]||0) * 0.4;
    return { ...p, score: scoreProduct(p, currentUser, clickBoost), reason: getReason(p, currentUser) };
  }).sort((a,b) => b.score - a.score).slice(0, 8);

  document.getElementById('appProducts').innerHTML = scored.map((p, i) => `
    <div class="app-product-item r${Math.min(i+1,6)}" onclick="clickProduct(${p.id})">
      <div class="app-item-emoji">${p.emoji}</div>
      <div class="app-item-body">
        <div class="app-item-name">${p.name} ${i<3?`<span class="rank-badge">#${i+1}</span>`:''} ${clicks[p.id]?`<span style="font-size:9px;background:#e8f5e9;color:#2db47d;padding:1px 4px;border-radius:3px">看过${clicks[p.id]}次</span>`:''}</div>
        <div class="app-item-shop">${p.shop}</div>
        <div><span class="app-item-tag">${p.reason}</span></div>
      </div>
      <div class="app-item-price">¥${p.price}</div>
    </div>
  `).join('');
}

